% Figure_EventStudy.m
%
% Purpose: plot the event study estimation results
%
% Input: see the regression results generated by STATA
%

clear
close all 
clc

%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
% 1. PREPARE
%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%

% point estimates
points_fish   = [.4410789 .8930367 .6420518 .559891 .672201 0 -.4588928 -1.687627]';
points_sail   = [-0.5355941 -0.7306929 -0.6372657 -0.5134022 -0.5909835 0 0.5485563 1.673127]';
points_CCAMLR = [-0.0068767 0.0504668 0.0043523 0.0209461 0.0025322 0 0.0185074 0.0197261]';

% 95% bounds
LB_fish = abs([-1.868562 -1.499016 -1.105751 -1.108166 -1.056919 0 -1.347776 -2.975765]'-points_fish);
UB_fish = abs(points_fish-[2.75072 3.285089 2.389854 2.227948 2.401321 0 0.4299906 -0.3994887]');

LB_sail = abs([-2.725679 -3.070359 -2.289632 -2.099052 -2.249468 0 -0.4121229 0.3468421]'-points_sail);
UB_sail = abs(points_sail-[1.654491 1.608973 1.015101 1.072248 1.067501 0 1.509236 2.999411]');

LB_CCAMLR = abs([-0.0836731 -0.0178533 -0.0561743 -0.0343973 -0.051269 0 -0.0257559 -0.0357775]'-points_CCAMLR);
UB_CCAMLR = abs(points_CCAMLR-[0.0699197 0.1187869 0.0648789 0.0762896 0.0563333 0 0.0627707 0.0752297]');

%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
% 2. PLOT
%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%

% aux line
auxX   = [0.2 8.8];
auxY   = [0 0];
auxX2  = [6 6];
auxY2  = [-3.5 3.5];
auxX3  = [6 6];
auxY3  = [-0.13 0.13];

auxX_fish   = [1 2 3 4 5 6 7 8];
auxX_sail   = [1 2 3 4 5 6 7 8];
auxX_CCAMLR = [1 2 3 4 5 6 7 8];


figure
subplot(3,1,1)
plot(auxX,auxY,...
    'LineStyle','--',...
    'Color',[0.6,0.6,0.6],...
    'LineWidth',1);
hold all
plot(auxX2,auxY2,...
    'LineStyle','--',...
    'Color',[0.6,0.6,0.6],...
    'LineWidth',1);
errorbar(auxX_fish,points_fish,LB_fish,UB_fish,...
    'LineStyle','none',...
    'Color','k',...
    'LineWidth',2,...
    'Marker','o')
title('(a) Fishing hours',...
    'Fontname', 'times new roman','FontSize',16.,...
    'Interpreter', 'latex')
ylabel({'Coefficient ($\beta_k$)'},...
    'Fontname', 'times new roman','FontSize',16,...
    'Interpreter', 'latex')
xlim([0.2,8.8])
ylim([-3.5,3.5])
set(gca,'XTick',[1,2,3,4,5,6 7 8],...
        'YTick',[-3,-2,-1,0,1,2,3],...
        'XTickLabel',{'11/12';'12/13';'13/14';'14/15';'15/16';'16/17';'17/18';'18/19'},...
        'YTickLabel',{'-3';'-2';'-1';'0';'1';'2';'3'},...
        'Fontname', 'times new roman','FontSize',12,...
        'box','off')

subplot(3,1,2)
plot(auxX,auxY,...
    'LineStyle','--',...
    'Color',[0.6,0.6,0.6],...
    'LineWidth',1);
hold all
plot(auxX2,auxY2,...
    'LineStyle','--',...
    'Color',[0.6,0.6,0.6],...
    'LineWidth',1);
errorbar(auxX_sail,points_sail,LB_sail,UB_sail,...
    'LineStyle','none',...
    'Color','k',...
    'LineWidth',2,...
    'Marker','o')
title('(b) Non-fishing hours',...
    'Fontname', 'times new roman','FontSize',16.,...
    'Interpreter', 'latex')
ylabel({'Coefficient ($\beta_k$)'},...
    'Fontname', 'times new roman','FontSize',16,...
    'Interpreter', 'latex')
xlim([0.2,8.8])
ylim([-3.5,3.5])
set(gca,'XTick',[1,2,3,4,5,6 7 8],...
        'YTick',[-3,-2,-1,0,1,2,3],...
        'XTickLabel',{'11/12';'12/13';'13/14';'14/15';'15/16';'16/17';'17/18';'18/19'},...
        'YTickLabel',{'-3';'-2';'-1';'0';'1';'2';'3'},...
        'Fontname', 'times new roman','FontSize',12,...
        'box','off')

subplot(3,1,3)
plot(auxX,auxY,...
    'LineStyle','--',...
    'Color',[0.6,0.6,0.6],...
    'LineWidth',1);
hold all
plot(auxX3,auxY3,...
    'LineStyle','--',...
    'Color',[0.6,0.6,0.6],...
    'LineWidth',1);
errorbar(auxX_CCAMLR,points_CCAMLR,LB_CCAMLR,UB_CCAMLR,...
    'LineStyle','none',...
    'Color','k',...
    'LineWidth',2,...
    'Marker','o')
title('(c) CCAMLR Fishing',...
    'Fontname', 'times new roman','FontSize',16.,...
    'Interpreter', 'latex')
xlabel('Season',...
    'Fontname', 'times new roman','FontSize',16.,...
    'Interpreter', 'latex')
ylabel({'Coefficient ($\beta_k$)'},...
    'Fontname', 'times new roman','FontSize',16,...
    'Interpreter', 'latex')
xlim([0.2,8.8])
ylim([-0.13,0.13])
set(gca,'XTick',[1,2,3,4,5,6 7 8],...
        'YTick',[-0.1,-0.05,0,0.05,0.1],...
        'XTickLabel',{'11/12';'12/13';'13/14';'14/15';'15/16';'16/17';'17/18';'18/19'},...
        'YTickLabel',{'-0.10';'-0.05';'0';'0.05';'0.10'},...
        'Fontname', 'times new roman','FontSize',12,...
        'box','off')